var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"너희가 우릴 속이고 가짜 약을 팔았잖아! 끝까지 발뺌할 셈이야?","JPN":"お前らが俺たちを騙して偽の薬を売ったんだろ！　しらばっくれるつもりかよ？","ENG":"You cheated us and sold us fake drugs! Are you seriously gonna keep denying that?","TWN":"明明就是你們先騙我們，賣我們假藥！還死不承認嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"그러니까 그건 오해라고. 우리가 판 건 분명 제대로 된 엘릭서였어.","JPN":"だから、それは誤解だって。俺らが売ったのは確かにちゃんとしたエリクサーだったんだよ。","ENG":"Like I said, it's just a misunderstanding. What we sold you was a proper Elixir.","TWN":"就跟你說是誤會，我們賣的是正牌的聖水。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L5_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"고작 엘릭서 0.1%에 물만 섞어서 팔아놓고선 뭐가 어째?!","JPN":"エリクサー0.1％の水割りを売っておいて、何だと！？","ENG":"More like properly diluted 0.1% Elixir! Are you kidding me?!","TWN":"什麼正牌的，聖水的成分明明就只有0.1%，其他都是水！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"어이, 네 녀석들이 부주의한 탓에 경찰들 미행이 붙어서 우리 장사 망칠 뻔한 건 기억 안 나?","JPN":"おい、てめえらの不注意で警察に尾行されて、俺らの商売が頓挫しそうになったことは覚えてねえのか？","ENG":"Hey, don't you remember that because of your mistake, the cops started following us, and we almost had to close shop?","TWN":"喂！你們忘記是誰不小心被條子盯上，害我們做不成生意的嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"그건 어떻게 배상할 건데?","JPN":"それはどうやって弁償すんだよ！","ENG":"Now, how are you going to compensate me for that?","TWN":"你們打算怎麼賠償？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"뭐…? 그게 어째서 우리 잘못이야!","JPN":"は……？　なんでそれが俺らのせいなんだ！？","ENG":"What...? How's that even our fault?!","TWN":"什麼…？關我們什麼事？！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"우린 카운터야. 너희 아지트를 뒤집어 놓기 전에 어서 제대로 된 엘릭서를 내놓던가 돈을 돌려줘!","JPN":"俺らはカウンターだ。お前らのアジトをハチの巣にする前に、とっとと本物のエリクサーを出すか、金を返せ！","ENG":"We're Counters. Now give us a proper Elixir or our money back before we trash your little hideout!","TWN":"我們可是制裁者，在我們把你們的窩掀掉前，看是要拿正品來，還是要把錢還來！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"얘들아. 저 카운터 나으리들이 우릴 혼내준댄다.","JPN":"おい、お前ら、あのカウンターの殿方が俺らのことをとっちめるってよ。","ENG":"Did you all hear that? These mighty Counters are going to punish us!","TWN":"喂，制裁者大人說要把我們窩掀掉欸。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BULLY_NPC_ACADEMY_CROWD","text":{"KOREA":"푸하하하!!","JPN":"ガハハハッ！！","ENG":"HAHAHAHA!","TWN":"噗哈哈哈！！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_LAUGH"},{"id":"L14_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"뭐, 뭐야? 왜 웃는데? 우리가 우스워?","JPN":"な、何だよ？　何がおかしいんだよ？","ENG":"W-what?! Why are you laughing? You think this is funny?!","TWN":"笑，笑什麼？我們很好笑嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"쳇, 더는 못 참아!","JPN":"チッ、もう我慢できない！","ENG":"Tch! I'm not holding back anymore!","TWN":"嘖，欠揍！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"크앗…!","JPN":"くあっ……！","ENG":"Kuh...!","TWN":"唔呃…！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"우리 힘이… 밀린다고?","JPN":"俺らが力で……負けてる？","ENG":"How's he... stronger than us?","TWN":"我們竟然…打不贏？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"어때, 성능 좋지? 너희 정도를 상대하는 덴 이 물을 탄 엘릭서 정도로도 충분하거든.","JPN":"どうだ、性能抜群だろ？　お前ら相手には、この水割りエリクサーだけで十分だ。","ENG":"What do you think? Good stuff, right? I can handle both of you even with this diluted Elixir.","TWN":"如何？性能不錯吧？雖然是用水稀釋過的聖水，但拿來對付你們綽綽有餘。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L21_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"이 자식이…!","JPN":"てめぇ……！","ENG":"Why you little...!","TWN":"你這傢伙…！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"으악!","JPN":"うわっ！","ENG":"Agh!","TWN":"呃啊！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_FIGHT"},{"id":"L25_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"어그로! 괜찮아?!","JPN":"アグロ！　大丈夫か！？","ENG":"Aggro! You okay?!","TWN":"阿格洛！你還好嗎？！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"우리가 너희처럼 엘릭서를 찾아 헤매는 카운터를 처음 보는 줄 아냐?","JPN":"俺らがお前らみたいにエリクサーを探し回ってるカウンターに初めて会ったと思ってんか？","ENG":"You think you're the first Counters looking for the Elixir?","TWN":"你以為你們是第一個來找我們買聖水的制裁者嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"애초에 힘 멀쩡한 카운터들이 뭐가 아쉬워서 그 비싼 돈을 주고 엘릭서를 찾겠어?","JPN":"そもそも、それなりの力を持ってるカウンターは大枚はたいてエリクサーなんて求めねえよ。","ENG":"After all, why would strong Counters need this expensive Elixir in the first place?","TWN":"要是厲害的制裁者，怎麼會捨得花大錢來買聖水？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"보나마나 명찰만 카운터일 뿐인, 열등감에 찬 D급 중의 D급 애송이들일 텐데 말이지.","JPN":"どうせ名だけの、劣等感にまみれたDランク小僧なんだろ？","ENG":"It's only the weakest Counters, the Grade D of all Grade Ds, who come looking for this stuff.","TWN":"想也知道你們這二個小鬼只是掛名的制裁者，實力根本是D級中的D級。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"큭…!","JPN":"くっ……！","ENG":"Khhk...!","TWN":"唔…！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"이제 어쩌지?","JPN":"どうする？","ENG":"What do we do now?","TWN":"現在怎麼辦？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"마침 잘 됐네. 카운터를 비싸게 사들이는 거래처를 하나 알고 있거든.","JPN":"ちょうどいい。カウンターを高く買い取る取引先を一カ所知ってるんだ。","ENG":"But it's okay. Because I know someone who will buy any Counter, and for a good price at that.","TWN":"正好我知道一個專門高價收購制裁者的地方。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"너희를 이대로 붙잡아서…","JPN":"このままお前らを捕まえて……","ENG":"I'll just tie you guys up, and–","TWN":"我要把你們賣去那裡…"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"음?","JPN":"む？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"거기, 무슨 소란이야?","JPN":"おいっ、何の騒ぎだ？","ENG":"Hey! What was that about?","TWN":"那邊是在吵什麼？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BULLY_NPC_NULL_M","text":{"KOREA":"그게… 갑자기 여자애 하나가 다짜고짜 아지트로 쳐들어와서는…!","JPN":"それが……いきなり女の子がアジトに押しかけてきて……！","ENG":"Well... a girl just barged into our hideout, and–","TWN":"那個…有個小丫頭突然闖進來…！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BULLY_NPC_ACADEMY_CROWD","text":{"KOREA":"꼬맹이! 여기가 어디라고 함부로 들어와!","JPN":"チビ！　ここをどこだと思ってるんだ！","ENG":"Hey, kid! What the heck are you thinking, coming into a place like this?!","TWN":"小鬼！好大膽子，竟敢闖進來這裡！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"BULLY_NPC_ACADEMY_CROWD","text":{"KOREA":"못 가게 붙잡아!","JPN":"引き留めろ！","ENG":"Get her!","TWN":"把人給我抓起來！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BULLY_NPC_ACADEMY_CROWD","text":{"KOREA":"우아아악!","JPN":"うわああっ！","ENG":"Aaaahhh!!!","TWN":"呃啊啊啊！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"거슬리니까 전부 비켜!","JPN":"邪魔だから全員どいて！","ENG":"Outta my way, you lowlifes!","TWN":"真是礙眼，全都給我閃開！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"저건 또 뭐야?","JPN":"あれはまた何だ？","ENG":"What the heck is that?","TWN":"她又是誰？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"나이엘 블루스틸…?","JPN":"ナイエル・ブルースチール……？","ENG":"Isn't that Naielle Bluesteel...?","TWN":"奈爾‧布魯斯提爾…？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"쟨 전술시험에서 매번 순위권에 들던 엘리트잖아? 이런 곳엔 왜 온 거지?","JPN":"あいつ、戦術試験でいつもランキング上位にいたエリートだろ？　なんでこんなとこに来るんだよ？","ENG":"Isn't she the elite that's always in the top charts of our tactics exams? But, why's she here?","TWN":"她不是每次戰術考試都名列前茅的菁英嗎？她怎麼會來這裡？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"야! 니들! 뭔데 감히 우리 아카데미 애들을 건드려?","JPN":"ちょっと！　あんたたち！　なんでうちのアカデミーの生徒に手を出すの？","ENG":"Hey! You scum! How dare you harm one of our students?!","TWN":"喂！你們這些傢伙！竟敢碰我們學院的學生？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"이봐. 여긴 우리 아지트야. 멋대로 쳐들어온 건 너희라고.","JPN":"おい。ここは俺らのアジトだ。勝手にやってきたのはお前らの方だろ。","ENG":"Look. This is our territory. You're the one trespassing right now.","TWN":"小丫頭，這裡可是我們的地盤，是你們自己闖進來的好嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"아카데미에도 아카데미의 규칙이 있지 않나? 남의 안방에서 이렇게 행패를 부리면 안 되지.","JPN":"アカデミーにも校則ってもんがあるだろ？　他人の縄張りで暴れられちゃ困るぜ。","ENG":"The Academy has its own rules, doesn't it? You can't go around causing havoc at someone's home like this.","TWN":"學院沒有校規嗎？怎麼可以在別人的地盤撒野呢？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"그딴 거 모르겠고! 범죄자들 주제에 말이 많아! 예비 학생회 임원으로서 전부 해치워주지!","JPN":"そんなことはどうでもいい！　犯罪者のくせにいちいちうるさいわね！　生徒会の浦欠員として、全員やっつけてやる！","ENG":"Shut up, you criminals! Like I care about that! As the next member of the Academy's Student Council, I'll beat you all up!","TWN":"我不知道什麼校規啦！你們這些不良分子話還真多！身為學生會幹部候選人，我要把你們全都處理掉！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};